        // Hàm hỗ trợ tạo Style cho các nút Menu giúp code sạch hơn
        private void StyleMenuButton(Button btn, string text, int top)
        {
            // 1. Cấu hình màu sắc
            btn.BackColor = Color.Transparent;
            btn.ForeColor = Color.White;

            // 2. Loại bỏ viền
            btn.FlatStyle = FlatStyle.Flat;
            btn.FlatAppearance.BorderSize = 0;

            // 3. Hiệu ứng Hover/Click
            btn.FlatAppearance.MouseOverBackColor = Color.FromArgb(51, 65, 85);
            btn.FlatAppearance.MouseDownBackColor = Color.FromArgb(30, 41, 59);

            // 4. SỬA LỖI FONT TẠI ĐÂY:
            // Dùng overload chuẩn: new Font(tên_font, cỡ_chữ, kiểu_dáng)
            btn.Font = new Font("Segoe UI", 11F, FontStyle.Regular);

            // 5. Căn chỉnh nội dung
            btn.Text = "      " + text;
            btn.TextAlign = ContentAlignment.MiddleLeft;
            btn.Location = new Point(0, top);
            btn.Size = new Size(220, 50);
            btn.UseVisualStyleBackColor = false;
        }

